// ExecuteBeadRuntime is the SD-024 successor to ExecuteBeadOptions.
// Durable knobs (Harness, Model, Provider, ModelRef, Effort,
// ContextBudget, MirrorCfg) are stripped — they live on
// config.ResolvedConfig and are passed via ExecuteBeadWithConfig's
// rcfg argument. Only non-serializable plumbing and per-invocation
// runtime intent remain.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev     string // base git revision (default: HEAD)
	PromptFile  string // override prompt file (auto-generated if empty)
	WorkerID    string // from DDX_WORKER_ID env or caller
	BeadEvents  BeadEventAppender
	Service     agentlib.DdxAgent
	AgentRunner AgentRunner
}

// ExecuteBeadWithConfig is the SD-024 successor to ExecuteBead. It
// accepts a sealed ResolvedConfig (durable knobs) and an
// ExecuteBeadRuntime (plumbing + per-invocation intent), assembles an
// equivalent ExecuteBeadOptions, and delegates to ExecuteBead.
// Behavior is identical to ExecuteBead with an equivalently-populated
// ExecuteBeadOptions.
//
// Stage 3 of SD-024: this function exists alongside ExecuteBead;
// production callers have not migrated yet.
func ExecuteBeadWithConfig(ctx context.Context, projectRoot string, beadID string, rcfg config.ResolvedConfig, runtime ExecuteBeadRuntime, gitOps GitOps) (*ExecuteBeadResult, error) {
	opts := ExecuteBeadOptions{
		FromRev:       runtime.FromRev,
		Harness:       rcfg.Harness(),
		Model:         rcfg.Model(),
		Provider:      rcfg.Provider(),
		ModelRef:      rcfg.ModelRef(),
		Effort:        rcfg.Effort(),
		ContextBudget: rcfg.ContextBudget(),
		PromptFile:    runtime.PromptFile,
		WorkerID:      runtime.WorkerID,
		BeadEvents:    runtime.BeadEvents,
		MirrorCfg:     rcfg.MirrorConfig(),
		Service:       runtime.Service,
		AgentRunner:   runtime.AgentRunner,
	}
	return ExecuteBead(ctx, projectRoot, beadID, opts, gitOps)
}

// TestBeadConfigOpts names every durable knob the execute-bead worker
// reads via ResolvedConfig (per SD-024 §ExecuteBeadOptions →
// ExecuteBeadRuntime field classification). Tests must specify each
// field explicitly; there are no zero-value defaults that silently
// bypass real config.
//
// See SD-024 / TD-024 §Test config constructors and §Stage 3.
type TestBeadConfigOpts struct {
	Harness  string
	Model    string
	Provider string // CLI-only override, no durable home on AgentConfig
	ModelRef string // CLI-only override, no durable home on AgentConfig
	Effort   string // CLI-only override, no durable home on AgentConfig
	Mirror   *ExecutionsMirrorConfig
}

// NewTestConfigForBead returns a *Config that, when Resolve()d with
// the matching CLIOverrides, produces a ResolvedConfig whose
// execute-bead-relevant accessors return the values supplied in opts.
// Pure CLI-override fields (Provider, ModelRef, Effort) have no
// durable home on AgentConfig and must be applied at Resolve time via
// CLIOverrides.
func NewTestConfigForBead(opts TestBeadConfigOpts) *Config {
	cfg := &Config{
		Version: "1.0",
		Agent: &AgentConfig{
			Harness: opts.Harness,
			Model:   opts.Model,
		},
	}
	if opts.Mirror != nil {
		cfg.Executions = &ExecutionsConfig{Mirror: opts.Mirror}
	}
	return cfg
}

// TestBeadOverrides returns the CLIOverrides that, combined with the
// *Config produced by NewTestConfigForBead(opts), drive a Resolve call
// to a ResolvedConfig matching opts. Pure-override fields (Provider,
// ModelRef, Effort) have no durable home on *Config; they are applied
// at Resolve time only.
func TestBeadOverrides(opts TestBeadConfigOpts) CLIOverrides {
	return CLIOverrides{
		Provider: opts.Provider,
		ModelRef: opts.ModelRef,
		Effort:   opts.Effort,
	}
}

