// execute-bead path.
func TestExecuteBeadRuntimeDelegation_ZeroValueRcfgPanics(t *testing.T) {
	defer func() {
		if rec := recover(); rec == nil {
			t.Fatal("ExecuteBeadWithConfig with zero-value ResolvedConfig must panic via requireSealed")
